from flask import Flask, send_file, jsonify, g
import os
from io import BytesIO

app = Flask(__name__)

INVOICE_STORAGE_PATH = '/var/invoices'

def get_user_invoice_mapping():
    return {
        1: {'user_id': 1, 'filename': 'invoice_1.pdf'},
        2: {'user_id': 1, 'filename': 'invoice_2.pdf'},
        3: {'user_id': 2, 'filename': 'invoice_3.pdf'},
        4: {'user_id': 2, 'filename': 'invoice_4.pdf'},
        5: {'user_id': 3, 'filename': 'invoice_5.pdf'},
    }

@app.route('/api/invoices/<int:invoice_id>/download', methods=['GET'])
def download_invoice(invoice_id):
    user_id = g.user_id
    
    invoice_mapping = get_user_invoice_mapping()
    
    if invoice_id not in invoice_mapping:
        return jsonify({'error': 'Invoice not found'}), 404
    
    invoice_data = invoice_mapping[invoice_id]
    
    if invoice_data['user_id'] != user_id:
        return jsonify({'error': 'Unauthorized access to this invoice'}), 403
    
    invoice_filename = invoice_data['filename']
    invoice_path = os.path.join(INVOICE_STORAGE_PATH, invoice_filename)
    
    if not os.path.exists(invoice_path):
        return jsonify({'error': 'Invoice file not found on server'}), 404
    
    return send_file(
        invoice_path,
        mimetype='application/pdf',
        as_attachment=True,
        download_name=f'invoice_{invoice_id}.pdf'
    )

